@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="_content" @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-2 mb-2">
    <button class="btn btn-primary" @onclick="SaveAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSaved is not null)
    {
        <span class="text-muted">Last saved at @_lastSaved.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string _content = string.Empty;
    private string _savedContent = string.Empty;
    private DateTime? _lastSaved;
    private NotepadInterop? _interop;
    private System.Threading.Timer? _autoSaveTimer;

    private bool HasUnsavedChanges => _content != _savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            await _interop.InitializeAsync();

            var restored = await _interop.LoadAsync();
            if (restored is not null)
            {
                _content = restored;
                _savedContent = restored;
                StateHasChanged();
            }

            _autoSaveTimer = new System.Threading.Timer(
                async _ => await InvokeAsync(AutoSaveAsync),
                null,
                TimeSpan.FromSeconds(30),
                TimeSpan.FromSeconds(30));
        }
    }

    private async Task AutoSaveAsync()
    {
        if (HasUnsavedChanges)
        {
            await SaveAsync();
        }
    }

    private async Task SaveAsync()
    {
        if (_interop is null) return;
        await _interop.SaveAsync(_content);
        _savedContent = _content;
        _lastSaved = DateTime.Now;
        await _interop.SetBeforeUnloadAsync(false);
        StateHasChanged();
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;
        _content = string.Empty;
        _savedContent = string.Empty;
        _lastSaved = null;
        await _interop.ClearAsync();
        await _interop.SetBeforeUnloadAsync(false);
    }

    private async Task OnContentChanged()
    {
        if (_interop is not null && HasUnsavedChanges)
        {
            await _interop.SetBeforeUnloadAsync(true);
        }
    }

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        if (_autoSaveTimer is not null)
            await _autoSaveTimer.DisposeAsync();

        if (_interop is not null)
            await _interop.DisposeAsync();
    }
}

const STORAGE_KEY = 'notepad-content';

let beforeUnloadHandler = null;

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
}

export function load() {
    return localStorage.getItem(STORAGE_KEY);
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
}

export function setBeforeUnload(enable) {
    if (enable && !beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener('beforeunload', beforeUnloadHandler);
    } else if (!enable && beforeUnloadHandler) {
        window.removeEventListener('beforeunload', beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

export function dispose() {
    if (beforeUnloadHandler) {
        window.removeEventListener('beforeunload', beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
